  1	import * as React from 'react';
  2	import { S3Commands } from '@odf/shared/s3';
  3	import { RowComponentType } from '@odf/shared/table';
  4	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  5	import { sortRows } from '@odf/shared/utils';
  6	import { LaunchModal } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
  7	import { TFunction } from 'react-i18next';
  8	import { Link } from 'react-router-dom-v5-compat';
  9	import {
 10	  EmptyState,
 11	  EmptyStateVariant,
 12	  EmptyStateIcon,
 13	  EmptyStateBody,
 14	  EmptyStateHeader,
 15	  Spinner,
 16	  Label,
 17	} from '@patternfly/react-core';
 18	import { CubesIcon, FileIcon, FolderIcon } from '@patternfly/react-icons';
 19	import { ActionsColumn, Td, IAction } from '@patternfly/react-table';
 20	import { getBucketOverviewBaseRoute, PREFIX } from '../../../constants';
 21	import { SetObjectsDeleteResponse } from '../../../modals/s3-browser/delete-objects/DeleteObjectsModal';
 22	import { LazyDeleteObjectsModal } from '../../../modals/s3-browser/delete-objects/LazyDeleteModals';
 23	import { ObjectCrFormat, S3ProviderType } from '../../../types';
 24	import { getEncodedPrefix, replacePathFromName } from '../../../utils';
 25	import {
 26	  DownloadAndPreviewState,
 27	  onDownload,
 28	  onPreview,
 29	} from '../download-and-preview/download-and-preview';
 30	
 31	const LazyPresignedURLModal = React.lazy(
 32	  () => import('../../../modals/s3-browser/presigned-url/PresignedURLModal')
 33	);
 34	
 35	const getColumnNames = (t: TFunction): string[] => [
 36	  t('Name'),
 37	  t('Size'),
 38	  t('Type'),
 39	  t('Last modified'),
 40	  '',
 41	];
 42	const getVersioningColumnName = (t: TFunction): string => t('Version ID');
 43	
 44	const getDeleteInlineActionTitle = (
 45	  showVersioning: boolean,
 46	  isDeleteMarker: boolean,
 47	  t: TFunction
 48	) => {
 49	  if (isDeleteMarker) return t('Discard delete marker');
 50	
 51	  return showVersioning ? t('Delete this version') : t('Delete');
 52	};
 53	
 54	export const getInlineActionsItems = (
 55	  t: TFunction,
 56	  launcher: LaunchModal,
 57	  bucketName: string,
 58	  object: ObjectCrFormat,
 59	  s3Client: S3Commands,
 60	  downloadAndPreview: DownloadAndPreviewState,
 61	  setDownloadAndPreview: React.Dispatch<
 62	    React.SetStateAction<DownloadAndPreviewState>
 63	  >,
 64	  foldersPath: string,
 65	  setDeleteResponse: SetObjectsDeleteResponse,
 66	  refreshTokens: () => Promise<void>,
 67	  closeObjectSidebar: () => void,
 68	  showVersioning: boolean,
 69	  isVersioningEnabledOrSuspended: boolean
 70	): IAction[] => {
 71	  const isDeleteMarker = object?.isDeleteMarker;
 72	  return [
 73	    ...(!isDeleteMarker
 74	      ? [
 75	          {
 76	            title: (
 77	              <>
 78	                {downloadAndPreview.isDownloading
 79	                  ? t('Downloading')
 80	                  : t('Download')}
 81	                {downloadAndPreview.isDownloading && <Spinner size="sm" />}
 82	              </>
 83	            ),
 84	            onClick: () =>
 85	              onDownload(
 86	                bucketName,
 87	                object,
 88	                s3Client,
 89	                setDownloadAndPreview,
 90	                showVersioning
 91	              ),
 92	            isDisabled: downloadAndPreview.isDownloading,
 93	            shouldCloseOnClick: false,
 94	          },
 95	        ]
 96	      : []),
 97	    ...(!isDeleteMarker
 98	      ? [
 99	          {
100	            title: (
101	              <>
102	                {downloadAndPreview.isPreviewing
103	                  ? t('Previewing')
104	                  : t('Preview')}
105	                {downloadAndPreview.isPreviewing && <Spinner size="sm" />}
106	              </>
107	            ),
108	            onClick: () =>
109	              onPreview(
110	                bucketName,
111	                object,
112	                s3Client,
113	                setDownloadAndPreview,
114	                showVersioning
115	              ),
116	            isDisabled: downloadAndPreview.isPreviewing,
117	            shouldCloseOnClick: false,
118	          },
119	        ]
120	      : []),
121	    ...(!isDeleteMarker
122	      ? [
123	          {
124	            title: t('Share with presigned URL'),
125	            onClick: () =>
126	              launcher(LazyPresignedURLModal, {
127	                isOpen: true,
128	                extraProps: { bucketName, object, s3Client, showVersioning },
129	              }),
130	            isDisabled: isDeleteMarker,
131	          },
132	        ]
133	      : []),
134	    {
135	      title: getDeleteInlineActionTitle(showVersioning, isDeleteMarker, t),
136	      onClick: () =>
137	        launcher(LazyDeleteObjectsModal, {
138	          isOpen: true,
139	          extraProps: {
140	            foldersPath,
141	            bucketName,
142	            objects: [object],
143	            s3Client,
144	            setDeleteResponse,
145	            refreshTokens,
146	            closeObjectSidebar,
147	            showVersioning,
148	            isVersioningEnabledOrSuspended,
149	          },
150	        }),
151	      ...(isDeleteMarker && {
152	        description: t('Delete this marker to restore object'),
153	      }),
154	    },
155	  ];
156	};
157	
158	export const isRowSelectable = (row: ObjectCrFormat) => !row.isFolder;
159	
160	export const getColumns = (t: TFunction, showVersioning: boolean) => {
161	  const columnNames = getColumnNames(t);
162	  const versioningColumnName = getVersioningColumnName(t);
163	
164	  return [
165	    {
166	      columnName: columnNames[0],
167	      sortFunction: (a, b, c) => sortRows(a, b, c, 'metadata.name'),
168	    },
169	    ...(showVersioning
170	      ? [
171	          {
172	            columnName: versioningColumnName,
173	            sortFunction: (a, b, c) =>
174	              sortRows(a, b, c, 'apiResponse.versionId'),
175	          },
176	        ]
177	      : []),
178	    {
179	      columnName: columnNames[1],
180	      sortFunction: (a, b, c) => sortRows(a, b, c, 'apiResponse.size'),
181	    },
182	    {
183	      columnName: columnNames[2],
184	      sortFunction: (a, b, c) => sortRows(a, b, c, 'type'),
185	    },
186	    {
187	      columnName: columnNames[3],
188	      sortFunction: (a, b, c) => sortRows(a, b, c, 'apiResponse.lastModified'),
189	    },
190	    { columnName: columnNames[4] },
191	  ];
192	};
193	
194	export const TableRow: React.FC<RowComponentType<ObjectCrFormat>> = ({
195	  row: object,
196	  extraProps,
197	}) => {
198	  const { t } = useCustomTranslation();
199	
200	  const [downloadAndPreview, setDownloadAndPreview] =
201	    React.useState<DownloadAndPreviewState>({
202	      isDownloading: false,
203	      isPreviewing: false,
204	    });
205	
206	  const actionItemsRef = React.useRef<IAction[]>();
207	
208	  const {
209	    launcher,
210	    bucketName,
211	    foldersPath,
212	    s3Client,
213	    setDeleteResponse,
214	    refreshTokens,
215	    onRowClick,
216	    closeObjectSidebar,
217	    showVersioning,
218	    isVersioningEnabledOrSuspended,
219	  } = extraProps;
220	  const isFolder = object.isFolder;
221	  const name = replacePathFromName(object, foldersPath);
222	  const prefix = getEncodedPrefix(name, foldersPath);
223	  const isLatest = object?.isLatest;
224	  const isDeleteMarker = object?.isDeleteMarker;
225	  const providerType = s3Client.providerType as S3ProviderType;
226	
227	  const columnNames = getColumnNames(t);
228	  const versioningColumnName = getVersioningColumnName(t);
229	
230	  const actionItems = getInlineActionsItems(
231	    t,
232	    launcher,
233	    bucketName,
234	    object,
235	    s3Client,
236	    downloadAndPreview,
237	    setDownloadAndPreview,
238	    foldersPath,
239	    setDeleteResponse,
240	    refreshTokens,
241	    closeObjectSidebar,
242	    showVersioning,
243	    isVersioningEnabledOrSuspended
244	  );
245	  actionItemsRef.current = actionItems;
246	
247	  const onClick = () =>
248	    onRowClick(object, actionItemsRef, {
249	      setDeleteResponse,
250	      refreshTokens,
251	      closeObjectSidebar,
252	    });
253	
254	  return (
255	    <>
256	      <Td dataLabel={columnNames[0]} onClick={onClick}>
257	        {isFolder ? (
258	          <Link
259	            to={`${getBucketOverviewBaseRoute(bucketName, providerType)}?${PREFIX}=${prefix}`}
260	          >
261	            <span>
262	              <FolderIcon className="pf-v6-u-mr-xs" />
263	              {name}
264	            </span>
265	          </Link>
266	        ) : (
267	          <span>
268	            <FileIcon className="pf-v6-u-mr-xs" />
269	            {name}
270	            {isLatest && (
271	              <Label color="purple" className="pf-v6-u-ml-xs" isCompact>
272	                {t('Latest')}
273	              </Label>
274	            )}
275	            {isDeleteMarker && (
276	              <Label color="purple" className="pf-v6-u-ml-xs" isCompact>
277	                {t('Delete marker')}
278	              </Label>
279	            )}
280	          </span>
281	        )}
282	      </Td>
283	      {showVersioning && (
284	        <Td dataLabel={versioningColumnName} onClick={onClick}>
285	          {object.apiResponse.versionId}
286	        </Td>
287	      )}
288	      <Td dataLabel={columnNames[1]} onClick={onClick}>
289	        {object.apiResponse.size}
290	      </Td>
291	      <Td dataLabel={columnNames[2]} onClick={onClick}>
292	        {object.type}
293	      </Td>
294	      <Td dataLabel={columnNames[3]} onClick={onClick}>
295	        {object.apiResponse.lastModified}
296	      </Td>
297	      <Td dataLabel={columnNames[4]} isActionCell>
298	        {isFolder ? null : <ActionsColumn items={actionItems} />}
299	      </Td>
300	    </>
301	  );
302	};
303	
304	export const EmptyPage: React.FC<{}> = () => {
305	  const { t } = useCustomTranslation();
306	
307	  return (
308	    <EmptyState variant={EmptyStateVariant.lg}>
309	      <EmptyStateHeader
310	        titleText={t('No objects found')}
311	        icon={<EmptyStateIcon icon={CubesIcon} />}
312	        headingLevel="h4"
313	      />
314	      <EmptyStateBody>
315	        {t('You do not have any objects in this bucket')}
316	      </EmptyStateBody>
317	    </EmptyState>
318	  );
319	};

